    33→            'subtasks.*.estimated_hours' => 'nullable|numeric|min:0',
    34→        ]);
    35→
    36→        $maxPosition = $project->tasks()->where('status', $validated['status'])->max('position') ?? -1;
    37→        $validated['position'] = $maxPosition + 1;
    38→
    39→        $task = $project->tasks()->create(
    40→            collect($validated)->except('subtasks')->toArray()
    41→        );
    42→
    43→        foreach ($validated['subtasks'] ?? [] as $subtaskData) {
    44→            $task->subtasks()->create($subtaskData);
